mapper.select:
SELECT COUNT(*)
FROM restaurant r
JOIN place p ON r.restaurant_id = p.place_id
WHERE (
    6371 * acos(
        cos(#{lat} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng} * 3.14159 / 180)) + 
        sin(#{lat} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180)
    )
) <= #{radius}


    AND r.category = #{category}



    AND (
        SELECT NVL(ROUND(AVG(rating),1),0) 
        FROM review 
        WHERE place_id = p.place_id AND status = 'display'
    ) >= #{minRating}



    AND (p.name LIKE '%' || #{keyword} || '%')

SELECT restaurant_id, description, category, place_id, name, address, latitude, longitude, image_url, view_count, review_count, avg_rating, rnum FROM ( SELECT a.*, ROWNUM AS rnum FROM ( SELECT r.restaurant_id, r.description, r.category, p.place_id, p.name, p.address, p.latitude, p.longitude, p.image_url, p.view_count, (SELECT COUNT(*) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS review_count, (SELECT NVL(ROUND(AVG(rating), 1), 0) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS avg_rating, (6371 * acos( cos(#{lat} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng} * 3.14159 / 180)) + sin(#{lat} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180) )) AS distance FROM restaurant r JOIN place p ON r.restaurant_id = p.place_id WHERE r.status = 'OPEN'
AND p.name LIKE '%' || #{keyword} || '%'
AND r.category = #{category}
ORDER BY distance ASC ) a WHERE a.distance <= #{radius}
AND a.avg_rating >= #{minRating}
AND ROWNUM <= #{end}
) WHERE rnum >= #{start}

SELECT restaurant_id, place_id, name, latitude, longitude, image_url, avg_rating, review_count, view_count, category FROM ( SELECT r.restaurant_id, p.place_id, p.name, p.latitude, p.longitude, p.image_url, p.view_count, r.category, (SELECT COUNT(*) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS review_count, (SELECT NVL(ROUND(AVG(rating), 1), 0) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS avg_rating, (6371 * acos( cos(#{lat} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng} * 3.14159 / 180)) + sin(#{lat} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180) )) AS distance FROM restaurant r JOIN place p ON r.restaurant_id = p.place_id WHERE r.status = 'OPEN'
AND (p.name LIKE '%' || #{keyword} || '%')
AND r.category = #{category}
) a
a.distance <= #{radius}
AND a.avg_rating >= #{minRating}
ORDER BY a.distance ASC

SELECT COUNT(*)
FROM favorite
WHERE user_id = #{userId}
  AND place_id = #{placeId}

