mapper.select:
SELECT COUNT(*)
FROM accommodation a
JOIN place p ON a.accommodation_id = p.place_id
WHERE (
   6371 * acos(
       cos(#{lat} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng} * 3.14159 / 180)) + 
       sin(#{lat} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180)
   )
) <= #{radius}


   AND a.category = #{category}



   AND (
       SELECT NVL(ROUND(AVG(rating),1),0) 
       FROM review 
       WHERE place_id = p.place_id AND status = 'display'
   ) >= #{minRating}



   AND (p.name LIKE '%' || #{keyword} || '%')

SELECT accommodation_id, description, category, place_id, name, address, latitude, longitude, image_url, view_count, review_count, avg_rating, rnum FROM ( SELECT b.*, ROWNUM AS rnum FROM ( SELECT a.accommodation_id, a.description, a.category, p.place_id, p.name, p.address, p.latitude, p.longitude, p.image_url, p.view_count, (SELECT COUNT(*) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS review_count, (SELECT NVL(ROUND(AVG(rating), 1), 0) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS avg_rating, (6371 * acos( cos(#{lat} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng} * 3.14159 / 180)) + sin(#{lat} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180) )) AS distance FROM accommodation a JOIN place p ON a.accommodation_id = p.place_id WHERE a.status = 'OPEN'
AND p.name LIKE '%' || #{keyword} || '%'
AND a.category = #{category}
ORDER BY distance ASC ) b WHERE b.distance <= #{radius}
AND b.avg_rating >= #{minRating}
AND ROWNUM <= #{end}
) WHERE rnum >= #{start}

SELECT accommodation_id, place_id, name, latitude, longitude, image_url, avg_rating, review_count, view_count, category FROM ( SELECT a.accommodation_id, p.place_id, p.name, p.latitude, p.longitude, p.image_url, p.view_count, a.category, (SELECT COUNT(*) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS review_count, (SELECT NVL(ROUND(AVG(rating), 1), 0) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS avg_rating, (6371 * acos( cos(#{lat} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng} * 3.14159 / 180)) + sin(#{lat} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180) )) AS distance FROM accommodation a JOIN place p ON a.accommodation_id = p.place_id WHERE a.status = 'OPEN'
AND (p.name LIKE '%' || #{keyword} || '%')
AND a.category = #{category}
) b
b.distance <= #{radius}
AND b.avg_rating >= #{minRating}
ORDER BY b.distance ASC
